option.value:
#!/bin/bash set -e # Run Appium InspectUI tests directly with java, bypassing exec-maven-plugin. # Prereq: run 'appium - compile' first (or: mvn -s ../k8infra/settings-local.xml compile test-compile) # Working directory is already set to appium/ by the run config.
CP=$(mvn -s ../k8infra/settings-local.xml dependency:build-classpath -Dmdep.outputFile=/dev/stdout -q 2>/dev/null) CP="target/classes:target/test-classes:${CP}"
exec java -cp "${CP}" \ -Dsim.device="iPhone 16 Pro" \ -Dsim.version=26.1 \ -Dappium.host=127.0.0.1 \ -Dappium.port=4723 \ -Dappium.basePath=/ \ org.testng.TestNG testng-inspect.xml
